+        DType::F64 => ArrayStorage::F64(collect_fromiter_values(
+            iter.bind(py),
+            &scalar_type,
+            count,
+            |value| value.extract::<f64>(),
+        )?),
+        DType::Complex64
+        | DType::Complex128
+        | DType::Str
+        | DType::Structured
+        | DType::DateTime64
+        | DType::TimeDelta64 => {
+            let kwargs = PyDict::new(py);
+            kwargs.set_item("count", count)?;
+            return Ok(numpy
+                .getattr("fromiter")?
+                .call((iter.bind(py), dtype.bind(py)), Some(&kwargs))?
+                .unbind());
+        }
+    };
